import{_ as e,o as a,c as t,ag as r}from"./chunks/framework.ePeAWSvT.js";const d=JSON.parse('{"title":"COURS : VIH / SIDA","description":"","frontmatter":{},"headers":[],"relativePath":"matieres/sante/cours/VIH.md","filePath":"matieres/sante/cours/VIH.md"}'),n={name:"matieres/sante/cours/VIH.md"};function s(o,i,l,u,m,h){return a(),t("div",null,[...i[0]||(i[0]=[r('<h1 id="cours-vih-sida" tabindex="-1">COURS : VIH / SIDA <a class="header-anchor" href="#cours-vih-sida" aria-label="Permalink to &quot;COURS : VIH / SIDA&quot;">​</a></h1><h2 id="_1️⃣-definition" tabindex="-1">1️⃣ Définition <a class="header-anchor" href="#_1️⃣-definition" aria-label="Permalink to &quot;1️⃣ Définition&quot;">​</a></h2><p>Le VIH est un <strong>virus qui attaque le système immunitaire</strong>, pouvant évoluer vers le SIDA (syndrome d’immunodéficience acquise).</p><hr><h2 id="_2️⃣-transmission" tabindex="-1">2️⃣ Transmission <a class="header-anchor" href="#_2️⃣-transmission" aria-label="Permalink to &quot;2️⃣ Transmission&quot;">​</a></h2><ul><li>Relations sexuelles non protégées</li><li>Partage de seringues</li><li>Transmission mère-enfant</li><li>Transfusions sanguines contaminées</li></ul><hr><h2 id="_3️⃣-symptomes" tabindex="-1">3️⃣ Symptômes <a class="header-anchor" href="#_3️⃣-symptomes" aria-label="Permalink to &quot;3️⃣ Symptômes&quot;">​</a></h2><ul><li>Phase initiale : fièvre, fatigue, ganglions</li><li>Phase chronique : asymptomatique</li><li>SIDA : infections opportunistes, perte de poids, cancers</li></ul><hr><h2 id="_4️⃣-diagnostic" tabindex="-1">4️⃣ Diagnostic <a class="header-anchor" href="#_4️⃣-diagnostic" aria-label="Permalink to &quot;4️⃣ Diagnostic&quot;">​</a></h2><ul><li>Tests sérologiques (ELISA, Western blot)</li><li>Charge virale</li><li>Numération CD4</li></ul><hr><h2 id="_5️⃣-traitement" tabindex="-1">5️⃣ Traitement <a class="header-anchor" href="#_5️⃣-traitement" aria-label="Permalink to &quot;5️⃣ Traitement&quot;">​</a></h2><ul><li>Antirétroviraux (ARV)</li><li>Suivi régulier</li><li>Prévention des infections opportunistes</li></ul><hr><h2 id="_6️⃣-role-infirmier" tabindex="-1">6️⃣ Rôle infirmier <a class="header-anchor" href="#_6️⃣-role-infirmier" aria-label="Permalink to &quot;6️⃣ Rôle infirmier&quot;">​</a></h2><ul><li>Éducation sur la prévention</li><li>Surveillance de l’adhésion au traitement</li><li>Soutien psychologique</li></ul>',18)])])}const _=e(n,[["render",s]]);export{d as __pageData,_ as default};
